USE [Hutech_SecureQR]
GO

CREATE TABLE [Users] (
    [user_id] int NOT NULL,
    [username] varchar(50) NOT NULL,
    [password_hash] varchar(255) NOT NULL,
    [bank_account] varchar(20) NOT NULL,
    [bank_code] varchar(20) NOT NULL,
    [created_at] datetime NULL,
    [full_name] nvarchar(100) NULL,
    [role] varchar(20) NULL,
    [status] varchar(20) NULL,
    [short_name] nvarchar(50) NULL
);
GO

GO

CREATE TABLE [QR_Links] (
    [qr_id] varchar(50) NOT NULL,
    [user_id] int NULL,
    [expected_amount] bigint NOT NULL,
    [description] nvarchar(255) NULL,
    [hmac_signature] varchar(255) NOT NULL,
    [status] varchar(20) NULL,
    [created_at] datetime NULL,
    [token_id] int NULL,
    [account_no] varchar(50) NULL,
    [bank_code] varchar(50) NULL,
    [bank_account_id] int NULL
);
GO

GO

CREATE TABLE [Transactions_Ledger] (
    [tx_id] varchar(50) NOT NULL,
    [qr_id] varchar(50) NULL,
    [actual_amount] bigint NOT NULL,
    [payer_ip] varchar(50) NULL,
    [ai_risk_score] float NULL,
    [status] varchar(20) NOT NULL,
    [block_hash] varchar(255) NOT NULL,
    [created_at] datetime NULL,
    [transfer_content] nvarchar(MAX) NULL
);
GO

GO

CREATE TABLE [System_Settings] (
    [setting_key] varchar(50) NOT NULL,
    [setting_value] nvarchar(500) NULL
);
GO

GO

CREATE TABLE [Sepay_Tokens] (
    [id] int NOT NULL,
    [token_name] nvarchar(100) NOT NULL,
    [token_string] varchar(255) NOT NULL,
    [is_active] bit NULL,
    [created_at] datetime NULL
);
GO

GO

CREATE TABLE [Hutech_Blockchain] (
    [block_index] int NOT NULL,
    [timestamp] datetime NULL,
    [transactions_data] nvarchar(MAX) NULL,
    [nonce] int NULL,
    [previous_hash] varchar(256) NULL,
    [block_hash] varchar(256) NULL
);
GO

GO

CREATE TABLE [Bank_Accounts] (
    [id] int NOT NULL,
    [bank_code] varchar(20) NOT NULL,
    [account_number] varchar(50) NOT NULL,
    [account_name] nvarchar(100) NOT NULL,
    [sepay_token_id] int NULL,
    [is_active] bit NULL,
    [created_at] datetime NULL
);
GO

GO

CREATE TABLE [Products] (
    [id] varchar(50) NOT NULL,
    [name] nvarchar(255) NOT NULL,
    [price] decimal NOT NULL,
    [image] nvarchar(MAX) NULL,
    [stock] int NULL,
    [category] nvarchar(100) NULL
);
GO

GO

CREATE TABLE [Store_Orders] (
    [id] varchar(50) NOT NULL,
    [product_id] varchar(50) NOT NULL,
    [amount] decimal NOT NULL,
    [status] varchar(20) NOT NULL,
    [created_at] datetime NULL,
    [expires_at] datetime NULL,
    [payer_ip] varchar(50) NULL,
    [details] nvarchar(MAX) NULL,
    [customer_name] nvarchar(255) NULL,
    [customer_phone] varchar(20) NULL,
    [customer_address] nvarchar(MAX) NULL
);
GO

GO

